    92→
    93→			if (activeOnly) {
    94→				query = query.where('status', 'active');
    95→			}
    96→
    97→			const results = await query;
    98→
    99→			this.logger.debug(
   100→				`Found ${results.length} styles_mv records for ${styleIds.length} styleIds${activeOnly ? ' (active only)' : ''}`,
   101→			);
   102→			return results.map((result) =>
   103→				this.parseStylesMvData(result as unknown as IStylesMvBase),
   104→			);
