   112→	async findByBrands({
   113→		brands,
   114→		limit,
   115→		categoryId,
   116→	}: {
   117→		brands: string[];
   118→		limit: number;
   119→		categoryId?: number;
   120→	}): Promise<IStylesMvBase[]> {
   121→		if (brands.length === 0) {
   122→			return [];
   123→		}
   124→
   125→		const sanitizedBrands = this.sanitizeBrandNames(brands);
   126→		if (sanitizedBrands.length === 0) {
   127→			this.logger.warn('All brand names were filtered out during sanitization');
   128→			return [];
   129→		}
   130→
   131→		const dto = plainToInstance(FindByBrandsDto, { brands: sanitizedBrands, limit });
   132→		const errors = await validate(dto);
   133→		if (errors.length > 0) {
   134→			this.logger.error(
   135→				`Validation failed for findByBrands: ${this.formatValidationErrors(errors)}`,
   136→			);
   137→			throw new Error(`Validation failed: ${this.formatValidationErrors(errors)}`);
   138→		}
   139→
   140→		try {
   141→			let query = this.knexRead<BaseStylesMvDto>(this.tableName)
   142→				.whereNull('deleted_at')
   143→				.whereRaw('JSON_OVERLAPS(brand, ?)', [JSON.stringify(sanitizedBrands)]);
   144→
   145→			if (categoryId !== undefined) {
   146→				query = query.where('primary_category_id', categoryId);
   147→			}
   148→
   149→			const results = await query.limit(limit);
   150→
   151→			this.logger.debug(
   152→				`Found ${results.length} styles_mv records for brands: ${brands.join(', ')}`,
   153→			);
   154→			return results.map((result) =>
   155→				this.parseStylesMvData(result as unknown as IStylesMvBase),
   156→			);
   157→		} catch (error: unknown) {
   158→			const err = error instanceof Error ? error : new Error(String(error));
