   175→				.offset(offset);
   176→
   177→			this.logger.debug(`Found ${results.length} styles_mv records`);
   178→			return results.map((result) =>
   179→				this.parseStylesMvData(result as unknown as IStylesMvBase),
   180→			);
   181→		} catch (error: unknown) {
   182→			const err = error instanceof Error ? error : new Error(String(error));
