   188→	async count(): Promise<number> {
   189→		try {
   190→			const result = await this.knexRead(this.tableName)
   191→				.whereNull('deleted_at')
   192→				.count('* as count')
   193→				.first();
   194→
   195→			return Number(result?.['count'] ?? 0);
   196→		} catch (error: unknown) {
   197→			const err = error instanceof Error ? error : new Error(String(error));
   198→			this.logger.error(`Failed to count styles_mv: ${err.message}`);
   199→			throw err;
   200→		}
   201→	}
   202→
   203→	private parseStylesMvData(data: IStylesMvBase): IStylesMvBase {
   204→		return {
   205→			...data,
   206→			sizes: this.parseJsonField(data.sizes),
   207→			default_unit_prices: this.parseJsonField(data.default_unit_prices),
   208→			colors: this.parseJsonField(data.colors),
   209→			brand: this.parseJsonField(data.brand),
   210→			condensed_features: this.parseJsonField(data.condensed_features),
   211→			broad_category_names: this.parseJsonField(data.broad_category_names),
   212→			sub_category_names: this.parseJsonField(data.sub_category_names),
   213→			no_minimum: Boolean(data.no_minimum),
   214→		};
   215→	}
   216→
   217→	private parseJsonField<T>(field: T | string | null): T | null {
   218→		if (field === null || field === undefined) {
   219→			return null;
   220→		}
   221→		if (typeof field === 'string') {
   222→			try {
   223→				return JSON.parse(field) as T;
   224→			} catch {
   225→				return null;
   226→			}
   227→		}
   228→		return field;
   229→	}
   230→
   231→	private sanitizeBrandNames(brands: string[]): string[] {
   232→		const brandNamePattern = /^[a-zA-Z0-9\s_\-+.'&®™\/]+$/;
   233→		return brands.filter((brand) => {
   234→			if (typeof brand !== 'string' || brand.length === 0 || brand.length > 40) {
   235→				return false;
   236→			}
   237→			return brandNamePattern.test(brand);
   238→		});
   239→	}
   240→
   241→	private formatValidationErrors(errors: ValidationError[]): string {
   242→		return errors
   243→			.map(
   244→				(error) =>
   245→					`${error.property}: ${Object.values(error.constraints ?? {}).join(', ')}`,
   246→			)
   247→			.join('; ');
   248→	}
   249→}
