     1→export interface ConcurrencyPoolOptions<T, R> {
     2→	items: T[];
     3→	concurrency: number;
     4→	handler: (item: T) => Promise<R>;
     5→	onItemComplete?: (result: R, item: T) => void;
     6→	onItemError?: (error: unknown, item: T) => void;
     7→}
     8→
     9→export interface ConcurrencyPoolResult<R> {
    10→	results: R[];
    11→	errors: { error: unknown; index: number }[];
    12→}
    13→
    14→export async function runWithConcurrencyLimit<T, R>({
    15→	items,
    16→	concurrency,
    17→	handler,
    18→	onItemComplete,
    19→	onItemError,
    20→}: ConcurrencyPoolOptions<T, R>): Promise<ConcurrencyPoolResult<R>> {
    21→	const results: R[] = [];
    22→	const errors: { error: unknown; index: number }[] = [];
    23→	let currentIndex = 0;
    24→
    25→	async function processNext(): Promise<void> {
    26→		while (currentIndex < items.length) {
    27→			const index = currentIndex++;
    28→			const item = items[index];
    29→
    30→			if (item === undefined) {
    31→				continue;
    32→			}
    33→
    34→			try {
    35→				const result = await handler(item);
    36→				results.push(result);
    37→				onItemComplete?.(result, item);
    38→			} catch (error) {
    39→				errors.push({ error, index });
    40→				onItemError?.(error, item);
    41→			}
    42→		}
    43→	}
    44→
    45→	const workers = Array.from({ length: Math.min(concurrency, items.length) }, () =>
    46→		processNext(),
    47→	);
    48→
    49→	await Promise.all(workers);
    50→
    51→	return { results, errors };
    52→}
    53→
    54→export async function* generateWithConcurrencyLimit<T, R>({
    55→	items,
    56→	concurrency,
    57→	handler,
    58→}: Omit<ConcurrencyPoolOptions<T, R>, 'onItemComplete' | 'onItemError'>): AsyncGenerator<
    59→	{ result: R; item: T } | { error: unknown; item: T }
    60→> {
    61→	const queue: (
    62→		| { type: 'result'; result: R; item: T }
    63→		| { type: 'error'; error: unknown; item: T }
    64→	)[] = [];
    65→	let resolveWaiting: (() => void) | null = null;
    66→	let currentIndex = 0;
    67→	let activeWorkers = 0;
    68→	let done = false;
    69→
    70→	async function processNext(): Promise<void> {
    71→		while (currentIndex < items.length) {
    72→			const index = currentIndex++;
    73→			const item = items[index];
    74→
    75→			if (item === undefined) {
    76→				continue;
    77→			}
    78→
    79→			try {
    80→				const result = await handler(item);
    81→				queue.push({ type: 'result', result, item });
    82→			} catch (error) {
    83→				queue.push({ type: 'error', error, item });
    84→			}
    85→
    86→			if (resolveWaiting) {
    87→				resolveWaiting();
    88→				resolveWaiting = null;
    89→			}
    90→		}
    91→
    92→		activeWorkers--;
    93→		if (activeWorkers === 0) {
    94→			done = true;
    95→			if (resolveWaiting) {
    96→				resolveWaiting();
    97→				resolveWaiting = null;
    98→			}
    99→		}
   100→	}
   101→
   102→	activeWorkers = Math.min(concurrency, items.length);
   103→	for (let i = 0; i < activeWorkers; i++) {
   104→		void processNext();
   105→	}
   106→
   107→	while (!done || queue.length > 0) {
   108→		if (queue.length === 0 && !done) {
   109→			await new Promise<void>((resolve) => {
   110→				resolveWaiting = resolve;
   111→			});
   112→		}
   113→
   114→		while (queue.length > 0) {
   115→			const entry = queue.shift();
   116→			if (entry) {
   117→				if (entry.type === 'result') {
   118→					yield { result: entry.result, item: entry.item };
   119→				} else {
   120→					yield { error: entry.error, item: entry.item };
   121→				}
   122→			}
   123→		}
   124→	}
   125→}
