     4→import { RedshiftTrendingItemsService } from '@modules/db/redshift/trending-items/redshift-trending-items.service';
     5→
     6→import { CronJobExecution } from '@decorators/cron-job-execution.decorator';
     7→
     8→interface PopulateTrendingItemsOptions {
     9→	startYear?: number;
    10→	endYear?: number;
    11→	months?: string;
    12→	lastWeek?: boolean;
    13→}
    14→
    15→@Command({
    16→	name: 'populate-trending-items',
    17→	description: 'Fetch order data from Redshift and populate product_annual_sales table',
    18→})
    19→export class PopulateTrendingItemsCommand extends CommandRunner {
    20→	private readonly logger = new Logger(PopulateTrendingItemsCommand.name);
    21→	private isShuttingDown = false;
    22→	private currentOperation: Promise<void> | null = null;
    23→
    24→	constructor(
    25→		private readonly redshiftTrendingItemsService: RedshiftTrendingItemsService,
    26→	) {
    27→		super();
    28→		this.setupGracefulShutdown();
    29→	}
    30→
    31→	@CronJobExecution({ jobName: 'populate-trending-items' })
    32→	async run(
    33→		_passedParams: string[],
    34→		options: PopulateTrendingItemsOptions,
    35→	): Promise<void> {
    36→		if (this.isShuttingDown) {
    37→			this.logger.warn('Command cancelled due to shutdown signal');
    38→			return;
    39→		}
    40→
    41→		try {
    42→			this.redshiftTrendingItemsService.resetCancellation();
    43→
    44→			if (options.lastWeek) {
    45→				this.logger.log('Processing last week data for cron job');
    46→				this.currentOperation =
    47→					this.redshiftTrendingItemsService.fetchAndProcessLastWeekData();
    48→				await this.currentOperation;
    49→				this.logger.log('Successfully updated trending items with last week data');
    50→				return;
    51→			}
    52→
    53→			const currentYear = new Date().getFullYear();
    54→			const startYear = options.startYear ?? currentYear - 5;
    55→			const endYear = options.endYear ?? currentYear;
    56→
    57→			let monthsToProcess: number[] | undefined;
    58→			if (options.months) {
    59→				monthsToProcess = options.months.split(',').map((m) => parseInt(m.trim(), 10));
    60→				if (monthsToProcess.some((m) => isNaN(m) || m < 1 || m > 12)) {
    61→					throw new Error('Invalid month values. Months must be between 1 and 12.');
    62→				}
    63→			}
    64→
    65→			// eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
    66→			if (this.isShuttingDown) {
    67→				this.logger.warn('Command cancelled due to shutdown signal');
    68→				return;
    69→			}
    70→
    71→			this.logger.log(
    72→				`Starting to populate trending items data from ${startYear} to ${endYear}`,
    73→			);
    74→
    75→			if (monthsToProcess) {
    76→				this.logger.log(`Processing only months: ${monthsToProcess.join(', ')}`);
    77→			}
    78→
    79→			this.currentOperation = this.redshiftTrendingItemsService.fetchAndProcessOrderData({
    80→				startYear,
    81→				endYear,
    82→				...(monthsToProcess && { monthsToProcess }),
    83→			});
    84→
    85→			await this.currentOperation;
    86→
    87→			// eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
    88→			if (!this.isShuttingDown) {
    89→				this.logger.log('Successfully populated trending items data');
    90→				return;
    91→			}
    92→		} catch (error) {
    93→			// eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
    94→			if (this.isShuttingDown) {
    95→				this.logger.warn('Command interrupted during shutdown');
    96→				return;
    97→			}
    98→			this.logger.error(`Failed to populate trending items: ${(error as Error).message}`);
    99→			process.exit(1);
   100→		} finally {
   101→			this.currentOperation = null;
   102→		}
   103→	}
   104→
   105→	@Option({
   106→		flags: '-s, --start-year <startYear>',
   107→		description: 'Start year for data fetching (default: 5 years ago)',
   108→	})
   109→	parseStartYear(value: string): number {
   110→		const year = parseInt(value, 10);
   111→		if (isNaN(year) || year < 1900 || year > 2100) {
   112→			throw new Error('Invalid start year');
   113→		}
   114→		return year;
   115→	}
   116→
   117→	@Option({
   118→		flags: '-e, --end-year <endYear>',
   119→		description: 'End year for data fetching (default: current year)',
   120→	})
   121→	parseEndYear(value: string): number {
   122→		const year = parseInt(value, 10);
   123→		if (isNaN(year) || year < 1900 || year > 2100) {
   124→			throw new Error('Invalid end year');
   125→		}
   126→		return year;
   127→	}
   128→
   129→	@Option({
   130→		flags: '-m, --months <months>',
   131→		description:
   132→			'Comma-separated list of months to process (1-12). If not specified, all months are processed',
   133→	})
   134→	parseMonths(value: string): string {
   135→		return value;
   136→	}
   137→
   138→	@Option({
   139→		flags: '-w, --last-week',
   140→		description: 'Process only last week data (for cron jobs)',
   141→	})
   142→	parseLastWeek(): boolean {
   143→		return true;
   144→	}
   145→
   146→	private setupGracefulShutdown(): void {
   147→		const signals: NodeJS.Signals[] = ['SIGTERM', 'SIGINT', 'SIGHUP', 'SIGQUIT'];
   148→
   149→		signals.forEach((signal) => {
   150→			process.on(signal, () => {
   151→				void this.handleShutdown(signal);
   152→			});
   153→		});
   154→
   155→		process.on('uncaughtException', (error) => {
   156→			this.logger.error(`Uncaught exception: ${error.message}`);
   157→			void this.handleShutdown('SIGTERM');
   158→		});
   159→
   160→		process.on('unhandledRejection', (reason) => {
   161→			this.logger.error(`Unhandled rejection: ${String(reason)}`);
   162→			void this.handleShutdown('SIGTERM');
   163→		});
   164→	}
   165→
   166→	private async handleShutdown(signal: string): Promise<void> {
   167→		if (this.isShuttingDown) {
   168→			this.logger.warn('Force shutdown requested, exiting immediately');
   169→			process.exit(1);
   170→		}
   171→
   172→		this.logger.warn(`Received ${signal} signal, initiating graceful shutdown...`);
   173→		this.isShuttingDown = true;
   174→
   175→		this.redshiftTrendingItemsService.cancelOperation();
   176→
   177→		try {
   178→			if (this.currentOperation) {
   179→				this.logger.log('Waiting for current operation to complete...');
   180→
   181→				const shutdownTimeout = setTimeout(() => {
   182→					this.logger.error('Graceful shutdown timeout, forcing exit');
   183→					process.exit(1);
   184→				}, 30000);
   185→
   186→				await this.currentOperation;
   187→				clearTimeout(shutdownTimeout);
   188→			}
   189→
   190→			this.logger.log('Graceful shutdown completed');
   191→			process.exit(0);
   192→		} catch (error) {
   193→			this.logger.error(`Error during shutdown: ${(error as Error).message}`);
   194→			process.exit(1);
   195→		}
   196→	}
   197→}
