     1→import { performance } from 'perf_hooks';
     2→
     3→import { Logger } from '@nestjs/common';
     4→
     5→import { rollbar } from '@config/rollbar.config';
     6→
     7→export interface CronJobExecutionOptions {
     8→	jobName: string;
     9→	context?: Record<string, unknown>;
    10→}
    11→
    12→function formatDuration(ms: number): string {
    13→	const seconds = Math.floor(ms / 1000);
    14→	const minutes = Math.floor(seconds / 60);
    15→	const hours = Math.floor(minutes / 60);
    16→
    17→	if (hours > 0) {
    18→		return `${hours}h ${minutes % 60}m ${seconds % 60}s`;
    19→	}
    20→
    21→	if (minutes > 0) {
    22→		return `${minutes}m ${seconds % 60}s`;
    23→	}
    24→
    25→	return `${seconds}s`;
    26→}
    27→
    28→export function CronJobExecution(options: CronJobExecutionOptions): MethodDecorator {
    29→	const { jobName, context = {} } = options;
    30→
    31→	return function (
    32→		target: unknown,
    33→		_propertyKey: string | symbol,
    34→		descriptor: PropertyDescriptor,
    35→	) {
    36→		const originalMethod = descriptor.value as (...args: unknown[]) => unknown;
    37→		const className = (target as { constructor: { name: string } }).constructor.name;
    38→		const logger = new Logger(className);
    39→
    40→		descriptor.value = async function (...args: unknown[]) {
    41→			const startTime = performance.now();
    42→
    43→			logger.log(`Starting ${jobName}`);
    44→			rollbar.info(`Starting ${jobName}`, {
    45→				command: jobName,
    46→				...context,
    47→			});
    48→
    49→			try {
    50→				await originalMethod.apply(this, args);
    51→
    52→				const executionTimeMs = performance.now() - startTime;
    53→
    54→				logger.log(`${jobName} completed. Duration: ${formatDuration(executionTimeMs)}`);
    55→				rollbar.info(`${jobName} completed`, {
    56→					command: jobName,
    57→					executionTimeMs,
    58→					executionTimeFormatted: formatDuration(executionTimeMs),
    59→					...context,
    60→				});
    61→
    62→				rollbar.wait(() => {
    63→					process.exit(0);
    64→				});
    65→			} catch (error) {
    66→				const executionTimeMs = performance.now() - startTime;
    67→
    68→				logger.error(
    69→					`${jobName} failed after ${formatDuration(executionTimeMs)}:`,
    70→					(error as Error).stack,
    71→				);
    72→				rollbar.error(`${jobName} failed`, {
    73→					command: jobName,
    74→					executionTimeMs,
    75→					executionTimeFormatted: formatDuration(executionTimeMs),
    76→					error: error instanceof Error ? error.message : String(error),
    77→					...context,
    78→				});
    79→
    80→				rollbar.wait(() => {
    81→					process.exit(1);
    82→				});
    83→			}
    84→		};
    85→
    86→		return descriptor;
    87→	};
    88→}
