    68→	@LogExecution()
    69→	async createIndex({
    70→		indexName,
    71→		mappings,
    72→		settings,
    73→	}: {
    74→		indexName: string;
    75→		mappings: Record<string, unknown>;
    76→		settings: Record<string, unknown>;
    77→	}): Promise<void> {
    78→		try {
    79→			const exists = await this.client.indices.exists({ index: indexName });
    80→
    81→			if (exists.body) {
    82→				this.logger.log(`Index ${indexName} already exists`);
