   100→
   101→	@LogExecution({ logParams: false, logResponse: false })
   102→	async bulkIndex({
   103→		indexName,
   104→		documents,
   105→	}: {
   106→		indexName: string;
   107→		documents: { _id: string; [key: string]: unknown }[];
   108→	}): Promise<{ indexed: number; errors: number }> {
   109→		try {
   110→			if (documents.length === 0) {
   111→				return { indexed: 0, errors: 0 };
   112→			}
   113→
   114→			const body = documents.flatMap((doc) => {
   115→				const { _id, ...docWithoutId } = doc;
   116→				return [{ index: { _index: indexName, _id } }, docWithoutId];
   117→			});
   118→
   119→			const response = await this.client.bulk({ body });
   120→
   121→			const errorItems = response.body.items.filter(
   122→				(item: { index?: { error?: unknown } }) => item.index?.error,
   123→			);
   124→
   125→			const errors = errorItems.length;
   126→			const indexed = documents.length - errors;
   127→
   128→			if (errors > 0) {
   129→				this.logger.warn(
   130→					`Bulk index completed with ${errors} errors out of ${documents.length} documents`,
   131→				);
   132→
   133→				const sampleErrors = errorItems
   134→					.slice(0, 3)
   135→					.map((item: { index?: { error?: { type?: string; reason?: string } } }) => ({
   136→						type: item.index?.error?.type,
   137→						reason: item.index?.error?.reason,
   138→					}));
   139→
   140→				this.logger.error(`Sample errors: ${JSON.stringify(sampleErrors, null, 2)}`);
   141→			}
   142→
   143→			return { indexed, errors };
   144→		} catch (error: unknown) {
   145→			this.handleError({ context: 'Bulk index failed', error });
   146→			throw error;
   147→		}
   148→	}
   149→
   150→	@LogExecution()
   151→	async deleteIndex({ indexName }: { indexName: string }): Promise<void> {
   152→		try {
   153→			const exists = await this.client.indices.exists({ index: indexName });
   154→
   155→			if (!exists.body) {
   156→				this.logger.log(`Index ${indexName} does not exist`);
   157→				return;
   158→			}
   159→
   160→			await this.client.indices.delete({ index: indexName });
   161→			this.logger.log(`Deleted OpenSearch index: ${indexName}`);
   162→		} catch (error: unknown) {
   163→			this.handleError({ context: `Failed to delete index ${indexName}`, error });
   164→			throw error;
   165→		}
   166→	}
   167→
   168→	private handleError({ context, error }: { context: string; error: unknown }): void {
   169→		const err = error instanceof Error ? error : new Error(String(error));
   170→		this.logger.error(`${context}: ${err.message}`, err.stack);
   171→	}
   172→}
