     1→import { Logger } from '@nestjs/common';
     2→import { Command, CommandRunner, Option } from 'nest-commander';
     3→
     4→import { StylesMvModel } from '@modules/db/styles-mv/models/styles-mv.model';
     5→import { EnvConfigService } from '@modules/env-config/env-config.service';
     6→import { OpensearchNeuralService } from '@modules/opensearch/opensearch-neural.service';
     7→
     8→import { runWithConcurrencyLimit } from '@utils/concurrency-pool.util';
     9→import { ProgressBar } from '@utils/progress-bar.util';
    10→
    11→import { OPENSEARCH_INDEX_NAME } from '@constants/env-variables.constant';
    12→
    13→import { CronJobExecution } from '@decorators/cron-job-execution.decorator';
    14→
    15→interface ReindexProductsNeuralOptions {
    16→	batchSize?: number;
    17→	concurrency?: number;
    18→	createIndex?: boolean;
    19→}
    20→
    21→@Command({
    22→	name: 'reindex-products-neural',
    23→	description: 'Sync styles_mv products to OpenSearch neural search index',
    24→})
    25→export class ReindexProductsNeuralCommand extends CommandRunner {
    26→	private readonly logger = new Logger(ReindexProductsNeuralCommand.name);
    27→	private isShuttingDown = false;
    28→	private currentOperation: Promise<void> | null = null;
    29→	private isCancelled = false;
    30→
    31→	constructor(
    32→		private readonly opensearchNeuralService: OpensearchNeuralService,
    33→		private readonly stylesMvModel: StylesMvModel,
    34→		private readonly configService: EnvConfigService,
    35→	) {
    36→		super();
    37→		this.setupGracefulShutdown();
    38→	}
    39→
    40→	@CronJobExecution({ jobName: 'reindex-products-neural' })
    41→	async run(
    42→		_passedParams: string[],
    43→		options: ReindexProductsNeuralOptions,
    44→	): Promise<void> {
    45→		if (this.isShuttingDown) {
    46→			this.logger.warn('Command cancelled due to shutdown signal');
    47→			return;
    48→		}
    49→
    50→		const batchSize = options.batchSize ?? 150;
    51→		const concurrency = options.concurrency ?? 5;
    52→		const createIndex = options.createIndex ?? false;
    53→
    54→		try {
    55→			const indexName = this.configService.get<string>({ key: OPENSEARCH_INDEX_NAME });
    56→
    57→			if (createIndex) {
    58→				this.logger.log(`Creating OpenSearch index: ${indexName}`);
    59→				await this.opensearchNeuralService.createProductsIndex({ indexName });
    60→			}
    61→
    62→			this.logger.log('Starting to reindex products to OpenSearch');
    63→			this.logger.log(`Batch size: ${batchSize}, Concurrency: ${concurrency}`);
    64→
    65→			const totalCount = await this.stylesMvModel.count();
    66→			this.logger.log(`Total products to index: ${totalCount}`);
    67→
    68→			if (totalCount === 0) {
    69→				this.logger.warn('No products found to index');
    70→				return;
    71→			}
    72→
    73→			const totalBatches = Math.ceil(totalCount / batchSize);
    74→			const batches = Array.from({ length: totalBatches }, (_, i) => ({
    75→				offset: i * batchSize,
    76→				limit: batchSize,
    77→			}));
    78→
    79→			const progressBar = new ProgressBar({ total: totalCount });
    80→			let totalIndexed = 0;
    81→			let totalErrors = 0;
    82→
    83→			this.currentOperation = this.processBatches({
    84→				batches,
    85→				concurrency,
    86→				indexName,
    87→				progressBar,
    88→				onBatchComplete: (indexed, errors) => {
    89→					totalIndexed += indexed;
    90→					totalErrors += errors;
    91→				},
    92→			});
    93→
    94→			await this.currentOperation;
    95→
    96→			if (!this.isCancelled) {
    97→				progressBar.finish();
    98→				this.logger.log('Successfully completed reindexing products to OpenSearch');
    99→				this.logger.log(
   100→					`Total indexed: ${totalIndexed}, Total errors: ${totalErrors}, Total processed: ${totalIndexed + totalErrors}`,
   101→				);
   102→			} else {
   103→				this.logger.warn('Reindexing was cancelled');
   104→			}
   105→		} catch (error) {
   106→			if (this.isShuttingDown || this.isCancelled) {
   107→				this.logger.warn('Command interrupted during shutdown');
   108→				return;
   109→			}
   110→			this.logger.error(`Failed to reindex products: ${(error as Error).message}`);
   111→			process.exit(1);
   112→		} finally {
   113→			this.currentOperation = null;
   114→		}
   115→	}
   116→
   117→	private async processBatches({
   118→		batches,
   119→		concurrency,
   120→		indexName,
   121→		progressBar,
   122→		onBatchComplete,
   123→	}: {
   124→		batches: { offset: number; limit: number }[];
   125→		concurrency: number;
   126→		indexName: string;
   127→		progressBar: ProgressBar;
   128→		onBatchComplete: (indexed: number, errors: number) => void;
   129→	}): Promise<void> {
   130→		await runWithConcurrencyLimit({
   131→			items: batches,
   132→			concurrency,
   133→			handler: async (batch) => {
   134→				if (this.isCancelled) {
   135→					return { indexed: 0, errors: 0 };
   136→				}
   137→
   138→				const styles = await this.stylesMvModel.findAll({
   139→					limit: batch.limit,
   140→					offset: batch.offset,
   141→				});
   142→
   143→				if (styles.length === 0) {
   144→					return { indexed: 0, errors: 0 };
   145→				}
   146→
   147→				const result = await this.opensearchNeuralService.bulkIndexProducts({
   148→					indexName,
   149→					styles,
   150→				});
   151→
   152→				return result;
   153→			},
   154→			onItemComplete: (result) => {
   155→				progressBar.increment(result.indexed + result.errors);
   156→				onBatchComplete(result.indexed, result.errors);
   157→			},
   158→			onItemError: (error) => {
   159→				this.logger.error(`Batch processing error: ${(error as Error).message}`);
   160→			},
   161→		});
   162→	}
   163→
   164→	@Option({
   165→		flags: '-b, --batch-size <batchSize>',
   166→		description: 'Number of products per batch (default: 150)',
   167→	})
   168→	parseBatchSize(value: string): number {
   169→		const size = parseInt(value, 10);
   170→		if (isNaN(size) || size < 1 || size > 1000) {
   171→			throw new Error('Batch size must be between 1 and 1000');
   172→		}
   173→		return size;
   174→	}
   175→
   176→	@Option({
   177→		flags: '-c, --concurrency <concurrency>',
   178→		description: 'Number of concurrent batch operations (default: 5)',
   179→	})
   180→	parseConcurrency(value: string): number {
   181→		const conc = parseInt(value, 10);
   182→		if (isNaN(conc) || conc < 1 || conc > 20) {
   183→			throw new Error('Concurrency must be between 1 and 20');
   184→		}
   185→		return conc;
   186→	}
   187→
   188→	@Option({
   189→		flags: '-i, --create-index',
   190→		description: 'Create index before reindexing',
   191→	})
   192→	parseCreateIndex(): boolean {
   193→		return true;
   194→	}
   195→
   196→	private setupGracefulShutdown(): void {
   197→		const signals: NodeJS.Signals[] = ['SIGTERM', 'SIGINT', 'SIGHUP', 'SIGQUIT'];
   198→
   199→		signals.forEach((signal) => {
   200→			process.on(signal, () => {
   201→				void this.handleShutdown(signal);
   202→			});
   203→		});
   204→
   205→		process.on('uncaughtException', (error) => {
   206→			this.logger.error(`Uncaught exception: ${error.message}`);
